def base32_secret(length_bytes: int = 20) -> str:
    return base64.b32encode(secrets.token_bytes(length_bytes)).decode("utf-8").rstrip("=")

def _hotp(key_bytes: bytes, counter: int, digits: int) -> str:
    msg = struct.pack(">Q", counter)
    h = hmac.new(key_bytes, msg, hashlib.sha1).digest()
    o = h[-1] & 0x0F
    code = (struct.unpack(">I", h[o:o+4])[0] & 0x7FFFFFFF) % (10 ** digits)
    return str(code).zfill(digits)

def totp(secret_b32: str, for_time: int = None, period: int = OTP_PERIOD, digits: int = OTP_DIGITS) -> str:
    if for_time is None:
        for_time = now_epoch()
